#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[129];
        scanf("%s", S);
        int N = strlen(S);
        int nim_sum = 0;
        for (int i = 0; i < N; i++) {
            if (S[i] == 'P') {
                nim_sum ^= i;
            }
        }
        if (nim_sum != 0) {
            printf("Yes\n");
        } else {
            printf("No\n");
        }
    }
    return 0;
}

