import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String S = sc.next();
            int N = S.length();
            int nim_sum = 0;
            for (int i = 0; i < N; i++) {
                if (S.charAt(i) == 'P') {
                    nim_sum ^= i;
                }
            }
            if (nim_sum != 0) {
                System.out.println("Yes");
            } else {
                System.out.println("No");
            }
        }
    }
}

